// Accept either a VAPI tool call wrapper or a plain dashboard POST.
const body = $input.first().json.body || $input.first().json;
const tenantSlug =
  body.message?.assistantOverrides?.variableValues?.tenant_slug
  || body.message?.variableValues?.tenant_slug
  || body.tenant_slug
  || 'bus-tz-pawa';
const tc = (body.message?.toolCalls || body.message?.toolCallList || [{}])[0] || {};
return [{ json: { tenant_slug: tenantSlug, toolCallId: tc.id || 'manual' } }];

const r = $input.first().json || {};
const p = $('Parse TBS Args').first().json;
const result = `Muhtasari wa leo:
Umehifadhiwa: ${r.held_count || 0}
Iliyothibitishwa: ${r.confirmed_count || 0}
Iliyofutwa: ${r.cancelled_count || 0}
Mapato: TZS ${Number(r.revenue_today || 0).toLocaleString()}`;
return [{ json: { results: [{ toolCallId: p.toolCallId, result }] } }];

const body = $input.first().json.body || $input.first().json;
const tenantSlug =
  body.message?.assistantOverrides?.variableValues?.tenant_slug
  || body.message?.variableValues?.tenant_slug
  || body.tenant_slug
  || 'bus-tz-pawa';
const tc = (body.message?.toolCalls || body.message?.toolCallList || [{}])[0] || {};
return [{ json: { tenant_slug: tenantSlug, toolCallId: tc.id || 'manual' } }];

const rows = $input.all().map(i => i.json).filter(r => r && r.ticket_code);
const p = $('Parse PH Args').first().json;
let result;
if (!rows.length) {
  result = 'Hakuna hifadhi inayosubiri kwa sasa.';
} else {
  result = 'Hifadhi zinazosubiri malipo:\n' + rows.map((r, i) => {
    const mins = Math.max(0, Math.round((new Date(r.expires_at) - new Date()) / 60000));
    return `${i + 1}. ${r.ticket_code} | ${r.passenger_name || '—'} (${r.passenger_phone || '—'}) | TZS ${Number(r.fare_tzs || 0).toLocaleString()} | dakika ${mins} zimebakia`;
  }).join('\n');
}
return [{ json: { results: [{ toolCallId: p.toolCallId, result }] } }];
